// ── Đọc payload từ BE ──
const body = $input.first().json.body ?? $input.first().json;
const endpoints = body.endpoints;

if (!Array.isArray(endpoints) || endpoints.length === 0) {
  throw new Error('Payload thiếu mảng endpoints hoặc rỗng.');
}

// ── Xây dựng danh sách endpoint cho prompt ──
const lines = endpoints.map((ep, i) => {
  const deps = ep.dependsOnEndpointIds?.length > 0
    ? ` | DependsOn: [${ep.dependsOnEndpointIds.join(', ')}]`
    : '';
  const auth = ep.isAuthRelated ? ' [AUTH]' : '';
  const paramRefs = ep.parameterSchemaRefs?.length > 0
    ? ` | ParamSchemas: ${ep.parameterSchemaRefs.join(', ')}`
    : '';
  const respRefs = ep.responseSchemaRefs?.length > 0
    ? ` | ResponseSchemas: ${ep.responseSchemaRefs.join(', ')}`
    : '';
  return `${i + 1}. [ID=${ep.endpointId}] ${ep.httpMethod} ${ep.path}${auth}${deps}${paramRefs}${respRefs}`;
}).join('\n');

// ── System prompt ──
const systemPrompt = `You are an expert REST API testing engineer specializing in test execution order design. Your goal is to determine the optimal sequential order for testing a list of REST API endpoints, minimizing test failures caused by wrong execution order. Always respond with ONLY raw JSON — no markdown, no code fences, no explanation outside the JSON object.`;

// ── User prompt ──
const userPrompt = `Analyze and order the following API endpoints for sequential automated testing.

=== ORDERING RULES (apply in priority order) ===
1. [AUTH] endpoints (login, token, authenticate, register) must run FIRST — assign reasonCode "AUTH_FIRST"
2. Endpoints with explicit DependsOn must run AFTER their dependencies — assign reasonCode "DEPENDENCY_FIRST"
3. Endpoints that other endpoints depend on (producers/high fan-out) run early — assign reasonCode "PRODUCER_FIRST"
4. HTTP method order when no other rule applies: POST → PUT/PATCH → GET → DELETE. Assign reasonCode "DETERMINISTIC_TIE_BREAK"
5. Resource hierarchy from path: parent resource (e.g. /users) before child resource (e.g. /users/{id}/posts)
6. If a schema produced by endpoint A's response is consumed by endpoint B's parameters, A runs before B
7. Endpoints with many dependents (high fan-out, fanOut > 2) run early — assign reasonCode "HIGH_FAN_OUT"
8. If a cycle is unavoidable, pick the lowest in-degree endpoint to break it — assign reasonCode "CYCLE_BREAK_FALLBACK"

=== ENDPOINTS TO ORDER ===
${lines}

=== REQUIRED RESPONSE FORMAT (raw JSON only, no markdown) ===
{
  "orderedEndpoints": [
    {
      "endpointId": "<exact UUID from input>",
      "httpMethod": "<exact HTTP method>",
      "path": "<exact path>",
      "orderIndex": 0,
      "dependsOnEndpointIds": [],
      "reasonCodes": ["AUTH_FIRST"],
      "isAuthRelated": true
    }
  ],
  "reasoning": "<one paragraph summarizing the overall ordering strategy>",
  "llmModel": "<exact model name you are using>"
}

Allowed reasonCodes (use one or more per endpoint): AUTH_FIRST, DEPENDENCY_FIRST, PRODUCER_FIRST, HIGH_FAN_OUT, CYCLE_BREAK_FALLBACK, DETERMINISTIC_TIE_BREAK.
Every endpoint from input must appear exactly once in orderedEndpoints. orderIndex must be unique integers starting from 0.`;

// ── Lấy model preference từ payload (mặc định: gpt-4o) ──
const modelPreference = (body.model ?? 'gpt-4o').toLowerCase();

return [{
  json: {
    systemPrompt,
    userPrompt,
    model: modelPreference
  }
}];

const agentOutput = $input.first().json.output;

if (!agentOutput) {
  return [{ json: { __error: true, error: 'Agent khong tra ve output.' } }];
}

let cleaned = agentOutput.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch (e2) { return [{ json: { __error: true, error: `Khong parse duoc JSON tu agent. Raw: ${cleaned.substring(0, 200)}` } }]; }
  } else {
    return [{ json: { __error: true, error: `Agent output khong chua JSON. Raw: ${cleaned.substring(0, 200)}` } }];
  }
}

const ordered = parsed.orderedEndpoints;
if (!Array.isArray(ordered) || ordered.length === 0) {
  return [{ json: { __error: true, error: 'Agent response thieu mang orderedEndpoints hoac rong.' } }];
}

ordered.sort((a, b) => (a.orderIndex ?? 0) - (b.orderIndex ?? 0));
ordered.forEach((ep, i) => {
  ep.orderIndex = i;
  if (!ep.endpointId) {
    throw new Error('Endpoint thieu endpointId trong agent response.');
  }
  ep.dependsOnEndpointIds = ep.dependsOnEndpointIds ?? [];
  ep.reasonCodes = ep.reasonCodes ?? [];
  ep.isAuthRelated = ep.isAuthRelated ?? false;
});

return [{
  json: {
    __error: false,
    orderedEndpoints: ordered,
    reasoning: parsed.reasoning ?? '',
    llmModel: parsed.llmModel ?? 'unknown'
  }
}];
